// export default PriceAnalytics;
import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";
import "./PriceAnalytics.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:7000/api";

const PriceAnalytics = () => {
  const [loading, setLoading] = useState(true);
  const [productList, setProductList] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [chartData, setChartData] = useState({ labels: [], datasets: [] });

  useEffect(() => {
    fetchDropdowns();
  }, []);

  const fetchDropdowns = async () => {
    try {
      const [products, categories] = await Promise.all([
        axios.get(`${API_BASE}/prices`),
        axios.get(`${API_BASE}/categories`),
      ]);
      setProductList(products.data.data || []);
      setCategoryList(categories.data.categories || []);
    } catch (err) {
      console.error("Dropdown error:", err);
    }
  };

  useEffect(() => {
    fetchChartData();
  }, [selectedProduct, selectedCategory, startDate, endDate]);

  const fetchChartData = async () => {
    setLoading(true);
    try {
      const query = `?product=${selectedProduct}&category=${selectedCategory}${
        startDate && endDate ? `&start=${startDate}&end=${endDate}` : ""
      }`;

      const response = await axios.get(`${API_BASE}/price-report/combined${query}`);
      const data = response.data || {};

      const labels = data.dates || [];
      const datasets = [];

      if (data.productTrends) {
        datasets.push({
          label: "Product Avg Price",
          data: data.productTrends.map((p) => p.avgPrice),
          borderColor: "#007bff",
          backgroundColor: "rgba(0,123,255,0.2)",
          fill: true,
          tension: 0.3,
        });
        datasets.push({
          label: "Product Difference",
          data: data.productTrends.map((p) => p.difference),
          borderColor: "#17a2b8",
          borderDash: [6, 3],
          fill: false,
          tension: 0.3,
        });
      }

      if (data.categoryTrends) {
        datasets.push({
          type: "bar",
          label: "Category Avg Price",
          data: data.categoryTrends.map((c) => c.avgPrice),
          backgroundColor: "rgba(40,167,69,0.5)",
        });
        datasets.push({
          type: "bar",
          label: "Category Difference",
          data: data.categoryTrends.map((c) => c.difference),
          backgroundColor: "rgba(255,193,7,0.5)",
        });
      }

      setChartData({ labels, datasets });
    } catch (err) {
      console.error("Error fetching chart data:", err);
      setChartData({ labels: [], datasets: [] });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Unified Price Analytics</h2>
      <p className="analytics-subtitle">
        Compare product and category price trends directly within one chart
      </p>

      {/* 🔹 Filter Controls */}
      <div className="filter-section">
        <div className="filter-group">
          <label>🧃 Product:</label>
          <select
            value={selectedProduct}
            onChange={(e) => setSelectedProduct(e.target.value)}
          >
            <option value="">All</option>
            {productList.map((p) => (
              <option key={p._id} value={p.name}>
                {p.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-group">
          <label>🗂️ Category:</label>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="">All</option>
            {categoryList.map((c) => (
              <option key={c._id} value={c.name}>
                {c.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-group">
          <label>📅 From:</label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
          />
        </div>

        <div className="filter-group">
          <label>➡️ To:</label>
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
          />
        </div>

        <button className="btn refresh" onClick={fetchChartData}>
          🔄 Refresh
        </button>
      </div>

      {/* 🔹 Combined Chart */}
      <div className="chart-wrapper">
        {loading ? (
          <div className="loading">Loading chart...</div>
        ) : chartData.labels.length > 0 ? (
          <div className="chart-container">
            <Bar
              data={chartData}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: "bottom",
                    labels: { color: "#333", boxWidth: 15 },
                  },
                  tooltip: {
                    callbacks: {
                      label: (context) =>
                        `${context.dataset.label}: ₹${context.parsed.y.toFixed(2)}`,
                    },
                  },
                },
                scales: {
                  x: { ticks: { color: "#333" } },
                  y: {
                    beginAtZero: true,
                    ticks: { color: "#333" },
                    title: { display: true, text: "Price (₹)" },
                  },
                },
              }}
            />
          </div>
        ) : (
          <p className="no-data">No data available for selected filters.</p>
        )}
      </div>
    </div>
  );
};

export default PriceAnalytics;
